#include<bits/stdc++.h>
using namespace std;
int t;
unsigned int a[16][16000]={0};
	unsigned int c[16]={0},n,x[16000],q;
void solve(){

	cin>>n;
	for(unsigned int i=1;i<=n;i++){
		cin>>x[i];
		if(c[x[i]]==0){
			c[x[i]]=i;
		}else{
			a[x[i]][c[x[i]]]=i;
			c[x[i]]=i;
		}
	}
	cin>>q;
	while(q--){
		unsigned int xx,y,ans=0;;
		cin>>xx>>y;
		for(unsigned int i=xx;i<=y;i++){
			if(a[x[i]][i]!=0&&a[x[i]][i]<=y){
				i=a[x[i]][i];
			}else{
				ans++;
			}
		}
		cout<<ans<<"\n";
	}
}
int main(){
    cin.tie(0);
    ios::sync_with_stdio(false);
	cin>>t;
	while(t--) solve();
	return 0;
}
